**Key Security Controls**:
- Algorithm pinning & expiration validation: `Validation::new(Algorithm::HS256)` ensures the token must be HS256 and not expired, preventing "alg" header tricks and long-lived tokens.
- Secret management & strength: The HMAC key is loaded from `JWT_HS256_SECRET` (not hard-coded) and checked for minimum length, reducing the risk of guessing or source-code leakage.
- Centralized auth extractor & authorization checks: `JwtAuth` encapsulates verification logic and the route still enforces server-side authorization, so claims are not blindly trusted for access control.

In production you want a layered approach: proper key management (and rotation), environment-aware config, structured logging, rate limiting, and careful error handling so attackers get minimal information while your observability is rich.

**PRODUCTION PATTERN**:

```rust
use axum::{
    async_trait,
    extract::{FromRequestParts, State, TypedHeader},
    http::{request::Parts, StatusCode},
    response::IntoResponse,
    routing::{get, post},
    Json, Router,
};
use chrono::{Duration, Utc};
use headers::authorization::Bearer;
use headers::Authorization;
use jsonwebtoken::{decode, encode, Algorithm, DecodingKey, EncodingKey, Header, Validation};
use serde::{Deserialize, Serialize};
use std::{collections::HashMap, net::SocketAddr, sync::Arc, time::Instant};
use tokio::sync::RwLock;
use tower::ServiceBuilder;
use tower_http::trace::TraceLayer;
use tracing::{error, info, Level};

// === Auth & Claims ===

#[derive(Debug, Serialize, Deserialize)]
struct Claims {
    sub: String,
    role: String,
    exp: usize,
    iss: String,
}

#[derive(Clone)]
struct KeyPair {
    kid: String,
    enc: EncodingKey,
    dec: DecodingKey,
}

#[derive(Clone, Default)]
struct KeyStore {
    active_kid: String,
    keys: HashMap<String, KeyPair>,
}

#[derive(Clone)]
struct AppState {
    keystore: Arc<RwLock<KeyStore>>,
    env: String,
}

impl AppState {
    async fn issue_token(&self, user_id: &str, role: &str) -> Result<String, String> {
        let ks = self.keystore.read().await;
        let kp = ks
            .keys
            .get(&ks.active_kid)
            .ok_or_else(|| "No active key".to_string())?;

        let exp = Utc::now() + Duration::minutes(15);
        let claims = Claims {
            sub: user_id.to_string(),
            role: role.to_string(),
            exp: exp.timestamp() as usize,
            iss: "my-api".to_string(),
        };

        let mut header = Header::new(Algorithm::HS256);
        header.kid = Some(kp.kid.clone());

        encode(&header, &claims, &kp.enc).map_err(|e| e.to_string())
    }
}

// === JWT Extractor with key rotation support ===

#[derive(Debug, Clone)]
struct AuthUser {
    user_id: String,
    role: String,
}

struct JwtAuth(AuthUser);

#[async_trait]
impl FromRequestParts<AppState> for JwtAuth {
    type Rejection = (StatusCode, String);

    async fn from_request_parts(
        parts: &mut Parts,
        state: &AppState,
    ) -> Result<Self, Self::Rejection> {
        let started = Instant::now();

        let TypedHeader(Authorization(bearer)) = TypedHeader::<Authorization<Bearer>>::from_request_parts(parts, state)
            .await
            .map_err(|_| (StatusCode::UNAUTHORIZED, "Missing bearer token".to_string()))?;

        let token_str = bearer.token();

        // Minimal parsing of header to get kid (jsonwebtoken doesn't expose header-only parse,
        // so for brevity we'll first try with active key; in a real system you'd maintain a
        // small set of recent keys and try by kid).
        let ks = state.keystore.read().await;
        let active = ks
            .keys
            .get(&ks.active_kid)
            .ok_or_else(|| (StatusCode::INTERNAL_SERVER_ERROR, "No active key".to_string()))?;

        let mut validation = Validation::new(Algorithm::HS256);
        validation.validate_exp = true;
        validation.set_issuer(&["my-api"]);

        // PRIMARY DEFENSE: strict validation & pinned algorithm
        let decoded =
            decode::<Claims>(token_str, &active.dec, &validation).or_else(|_e| {
                // Try all keys to support rotation grace period
                for (kid, kp) in ks.keys.iter() {
                    if kid == &ks.active_kid {
                        continue;
                    }
                    if let Ok(td) = decode::<Claims>(token_str, &kp.dec, &validation) {
                        return Ok(td);
                    }
                }
                Err((StatusCode::UNAUTHORIZED, "Invalid or expired token".to_string()))
            })?;

        // DEFENSE-IN-DEPTH: validate subject and role
        if decoded.claims.sub.is_empty() {
            return Err((StatusCode::UNAUTHORIZED, "Invalid subject".to_string()));
        }

        let user = AuthUser {
            user_id: decoded.claims.sub,
            role: decoded.claims.role,
        };

        info!(
            latency_ms = started.elapsed().as_millis() as u64,
            user_id = %user.user_id,
            "jwt_validated"
        );

        Ok(JwtAuth(user))
    }
}

// === Rate-limited login endpoint (simplified in-memory) ===

#[derive(Debug, Deserialize)]
struct LoginRequest {
    username: String,
    password: String,
}

#[derive(Debug, Serialize)]
struct LoginResponse {
    token: String,
}

// Simple in-memory rate limiter per username (for demo only)
#[derive(Default, Clone)]
struct LoginLimiter {
    attempts: Arc<RwLock<HashMap<String, (u32, Instant)>>>,
}

impl LoginLimiter {
    async fn check_and_increment(&self, username: &str) -> bool {
        let mut map = self.attempts.write().await;
        let now = Instant::now();
        let window = std::time::Duration::from_secs(60);
        let max_attempts = 5;

        let entry = map.entry(username.to_string()).or_insert((0, now));
        if now.duration_since(entry.1) > window {
            *entry = (0, now);
        }
        entry.0 += 1;
        entry.0 <= max_attempts
    }
}

async fn login_handler(
    State(state): State<AppState>,
    State(limiter): State<LoginLimiter>,
    Json(req): Json<LoginRequest>,
) -> impl IntoResponse {
    let allowed = limiter.check_and_increment(&req.username).await;
    if !allowed {
        info!(username = %req.username, "login_rate_limited");
        return (StatusCode::TOO_MANY_REQUESTS, "Too many attempts");
    }

    // TODO: verify password against DB hash; here we hardcode for demo
    if req.password != "CorrectHorseBatteryStaple" {
        info!(username = %req.username, "login_failed");
        tokio::time::sleep(std::time::Duration::from_millis(200)).await;
        return (StatusCode::UNAUTHORIZED, "Invalid credentials");
    }

    let role = "admin"; // Would come from DB
    match state.issue_token(&req.username, role).await {
        Ok(token) => {
            info!(username = %req.username, "login_success");
            (StatusCode::OK, Json(LoginResponse { token }))
        }
        Err(e) => {
            error!("token_issue_error: {}", e);
            (StatusCode::INTERNAL_SERVER_ERROR, "Unable to issue token")
        }
    }
}

async fn admin_handler(State(state): State<AppState>, JwtAuth(user): JwtAuth) -> impl IntoResponse {
    // DEFENSE-IN-DEPTH: enforce authorization at handler level
    if user.role != "admin" {
        info!(user_id = %user.user_id, "admin_forbidden");
        return (StatusCode::FORBIDDEN, "Forbidden");
    }

    let env = &state.env;
    let msg = format!("Admin area for {} (env={})", user.user_id, env);
    (StatusCode::OK, msg)
}

