    let username = "alice".to_string();

    let session_id = generate_session_id();
    let expires_at = OffsetDateTime::now_utc() + Duration::minutes(30);

    {
        let mut s = store.lock().unwrap();
        s.insert(
            session_id.clone(),
            Session { username: username.clone(), expires_at },
        );
    }

    let mut headers = HeaderMap::new();
    // PRIMARY DEFENSE: strong, random, opaque session ID with expiration
    headers.insert(
        "Set-Cookie",
        // Add security flags: Secure; HttpOnly; SameSite=Lax
        format!(
            "session_id={}; Path=/; Max-Age=1800; HttpOnly; SameSite=Lax",
            session_id
        )
        .parse()
        .unwrap(),
    );

    (StatusCode::OK, headers, "Logged in securely")
}

async fn dashboard(
    TypedHeader(cookie): TypedHeader<Cookie>,
    State(store): State<SessionStore>,
) -> impl IntoResponse {
    let session_id = match cookie.get("session_id") {
        Some(v) => v.to_string(),
        None => return StatusCode::UNAUTHORIZED.into_response(),
